/**
 * Delegate Command - Interactively select and delegate to subagents
 *
 * Provides:
 * - /delegate - opens agent selector with task input
 * - /agents   - lists available agents
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { discoverAgents } from "./subagent/agents.js";

export default function (pi: ExtensionAPI) {
	// List available agents
	pi.registerCommand("agents", {
		description: "List available subagents",
		handler: async (_args, ctx) => {
			const discovery = discoverAgents(ctx.cwd, "user");
			const projectDiscovery = discoverAgents(ctx.cwd, "project");

			if (discovery.agents.length === 0 && projectDiscovery.agents.length === 0) {
				ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "info");
				return;
			}

			const lines: string[] = [];

			if (discovery.agents.length > 0) {
				lines.push("User agents:");
				for (const agent of discovery.agents) {
					const tools = agent.tools?.join(", ") || "default";
					const model = agent.model ? ` (${agent.model})` : "";
					lines.push(`  ${agent.name}${model}`);
					lines.push(`    ${agent.description}`);
					lines.push(`    tools: ${tools}`);
				}
				lines.push("");
			}

			if (projectDiscovery.agents.length > 0) {
				lines.push("Project agents:");
				for (const agent of projectDiscovery.agents) {
					const tools = agent.tools?.join(", ") || "default";
					const model = agent.model ? ` (${agent.model})` : "";
					lines.push(`  ${agent.name}${model}`);
					lines.push(`    ${agent.description}`);
					lines.push(`    tools: ${tools}`);
				}
			}

			ctx.ui.setWidget("agents-list", lines);
		},
	});

	// Delegate - select agent and enter task
	pi.registerCommand("delegate", {
		description: "Delegate task to a subagent",
		async handler(args, ctx) {
			// Check for subagent tool
			const hasSubagentTool = pi.getAllTools?.().some((t: any) => t.name === "subagent");

			if (!hasSubagentTool) {
				ctx.ui.notify("Subagent extension not loaded. Please enable subagent extension.", "error");
				return;
			}

			const allAgents = [
				...discoverAgents(ctx.cwd, "user").agents,
				...discoverAgents(ctx.cwd, "project").agents,
			];

			if (allAgents.length === 0) {
				ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "error");
				return;
			}

			// Parse: /delegate agent:frontend-dev task:make a button
			let selectedAgent = "";
			let task = args.trim();

			if (args.includes("agent:")) {
				const match = args.match(/agent:(\S+)/);
				if (match) {
					selectedAgent = match[1];
					task = task.replace(/agent:\S+\s*/, "").trim();
				}
			}

			if (!selectedAgent) {
				// Show agent selector
				const choices = allAgents.map((a) => ({
					label: a.name,
					description: a.description,
					value: a.name,
				}));

				const choice = await ctx.ui.select("Select agent:", choices);

				if (!choice) {
					ctx.ui.notify("Cancelled", "info");
					return;
				}

				selectedAgent = choice;
			}

			if (!task) {
				// Prompt for task
				const result = await ctx.ui.input("Task", "What should the agent do?");

				if (!result) {
					ctx.ui.notify("Cancelled", "info");
					return;
				}

				task = result;
			}

			// Confirm and execute
			const agent = allAgents.find((a) => a.name === selectedAgent);
			if (!agent) {
				ctx.ui.notify(`Agent "${selectedAgent}" not found`, "error");
				return;
			}

			const ok = await ctx.ui.confirm(
				"Confirm",
				`Delegate to "${selectedAgent}"?\n\n${task.slice(0, 100)}${task.length > 100 ? "..." : ""}`,
			);

			if (!ok) {
				ctx.ui.notify("Cancelled", "info");
				return;
			}

			// Execute via subagent tool by sending a user message
			const toolCall = JSON.stringify({
				agent: selectedAgent,
				task: task,
			});

			// Send the task as a follow-up message that triggers subagent
			pi.sendUserMessage(`Use subagent tool to execute:\n\`\`\`json\n${toolCall}\n\`\`\``, {
				deliverAs: "followUp",
			});
		},
	});
}

/**
 * Subagent Interface - UI commands for delegating to subagents
 *
 * Provides:
 * - /delegate [agent:name] [task:text] - Select agent and delegate task
 * - /agents                           - List available agents
 */

import * as fs from "node:fs";
import * as path from "node:path";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { getAgentDir, parseFrontmatter } from "@mariozechner/pi-coding-agent";

interface AgentConfig {
	name: string;
	description: string;
	tools?: string[];
	model?: string;
	source: "user" | "project";
}

function discoverAgents(cwd: string, scope: "user" | "project" | "both"): { agents: AgentConfig[]; projectDir: string | null } {
	const userDir = path.join(getAgentDir(), "agents");
	let projectDir: string | null = null;

	// Find project agents dir
	let currentDir = cwd;
	while (currentDir !== path.dirname(currentDir)) {
		const candidate = path.join(currentDir, ".pi", "agents");
		if (fs.existsSync(candidate) && fs.statSync(candidate).isDirectory()) {
			projectDir = candidate;
			break;
		}
		currentDir = path.dirname(currentDir);
	}

	const loadAgents = (dir: string, source: "user" | "project"): AgentConfig[] => {
		if (!fs.existsSync(dir)) return [];

		const agents: AgentConfig[] = [];
		try {
			const files = fs.readdirSync(dir);
			for (const file of files) {
				if (!file.endsWith(".md")) continue;

				const filePath = path.join(dir, file);
				const content = fs.readFileSync(filePath, "utf-8");
				const { frontmatter, body: _body } = parseFrontmatter<Record<string, string>>(content);

				if (!frontmatter.name || !frontmatter.description) continue;

				agents.push({
					name: frontmatter.name,
					description: frontmatter.description,
					tools: frontmatter.tools?.split(",").map((t: string) => t.trim()).filter(Boolean),
					model: frontmatter.model,
					source,
				});
			}
		} catch { /* ignore */ }

		return agents;
	};

	const userAgents = scope === "project" ? [] : loadAgents(userDir, "user");
	const projectAgents = scope === "user" || !projectDir ? [] : loadAgents(projectDir, "project");

	const agentMap = new Map<string, AgentConfig>();
	for (const a of [...userAgents, ...projectAgents]) {
		agentMap.set(a.name, a);
	}

	return { agents: Array.from(agentMap.values()), projectDir };
}

export default function (pi: ExtensionAPI) {
	// List all available agents
	pi.registerCommand("agents", {
		description: "List available subagents",
		handler: async (_args, ctx) => {
			const { agents, projectDir } = discoverAgents(ctx.cwd, "both");

			if (agents.length === 0) {
				ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "info");
				return;
			}

			const userAgents = agents.filter((a) => a.source === "user");
			const projAgents = agents.filter((a) => a.source === "project");

			const lines: string[] = [];

			if (userAgents.length > 0) {
				lines.push("═══ User Agents ═══");
				for (const agent of userAgents) {
					const tools = agent.tools?.join(", ") || "default";
					lines.push(`${agent.name}`);
					lines.push(`  ${agent.description}`);
					if (agent.model) lines.push(`  model: ${agent.model}`);
					lines.push(`  tools: ${tools}`);
					lines.push("");
				}
			}

			if (projAgents.length > 0) {
				lines.push("═══ Project Agents ═══");
				for (const agent of projAgents) {
					const tools = agent.tools?.join(", ") || "default";
					lines.push(`${agent.name}`);
					lines.push(`  ${agent.description}`);
					if (agent.model) lines.push(`  model: ${agent.model}`);
					lines.push(`  tools: ${tools}`);
					lines.push("");
				}
			}

			if (projectDir) {
				lines.push(`Project agents from: ${projectDir}`);
			}

			ctx.ui.setWidget("agents-list", lines);
		},
	});

	// Delegate task to agent
	pi.registerCommand("delegate", {
		description: "Delegate task to a subagent",
		handler: async (args, ctx) => {
			const { agents } = discoverAgents(ctx.cwd, "both");

			if (agents.length === 0) {
				ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "error");
				return;
			}

			// Parse args: "agent:name task:text" or just "task"
			let selectedAgent = "";
			let task = args.trim();

			const agentMatch = args.match(/^(?:agent:)?(\S+?)(?:\s+(.+))?$/s);
			if (agentMatch) {
				const potentialAgent = agentMatch[1];
				// Check if it's a valid agent name
				const found = agents.find((a) => a.name === potentialAgent);
				if (found) {
					selectedAgent = potentialAgent;
					task = agentMatch[2]?.trim() || "";
				}
			}

			// Interactive agent selection if not specified
			if (!selectedAgent) {
				const choice = await ctx.ui.select("Select Agent:", agents.map((a) => ({
					label: a.name,
					description: a.description,
					value: a.name,
				})));

				if (!choice) {
					ctx.ui.notify("Cancelled", "info");
					return;
				}

				selectedAgent = choice;
			}

			// Interactive task input if not specified
			if (!task) {
				const result = await ctx.ui.input("Task", "What should the agent do?");
				if (!result) {
					ctx.ui.notify("Cancelled", "info");
					return;
				}
				task = result;
			}

			// Confirm
			const ok = await ctx.ui.confirm(
				"Confirm",
				`Delegate to "${selectedAgent}"?\n\n${task.slice(0, 100)}${task.length > 100 ? "..." : ""}`,
			);

			if (!ok) {
				ctx.ui.notify("Cancelled", "info");
				return;
			}

			// Check if subagent tool exists
			const tools = pi.getAllTools?.() || [];
			const hasSubagent = tools.some((t: any) => t.name === "subagent");

			if (hasSubagent) {
				// Use subagent tool directly
				pi.sendUserMessage(`Use subagent to execute:\n\`\`\`json\n${JSON.stringify({ agent: selectedAgent, task }, null, 2)}\n\`\`\``, {
					deliverAs: "followUp",
				});
			} else {
				// Fallback: open agent file for review
				const agentDir = path.join(getAgentDir(), "agents");
				const agentFile = path.join(agentDir, `${selectedAgent}.md`);

				if (fs.existsSync(agentFile)) {
					ctx.ui.setEditorText(`Task: ${task}\n\n---\n\n${fs.readFileSync(agentFile, "utf-8")}`);
					ctx.ui.notify(`Opened ${selectedAgent}.md - use /fork to start subagent session`, "info");
				} else {
					ctx.ui.notify(`Agent "${selectedAgent}" file not found`, "error");
				}
			}
		},
	});
}

/**
 * Agent Status Footer - Shows active agent + model in footer with clickable selection
 *
 * Features:
 * - Displays 🤖 agent + 🧠 model in footer
 * - Click to change agent or model
 * - Updates automatically when agent changes (via subagent tool)
 */

import * as fs from "node:fs";
import * as path from "node:path";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { getAgentDir, parseFrontmatter } from "@mariozechner/pi-coding-agent";

// ═══════════════════════════════════════════════════════════════════════════════
// TYPES
// ═══════════════════════════════════════════════════════════════════════════════

interface AgentConfig {
	name: string;
	description: string;
	tools?: string[];
	model?: string;
	source: "user" | "project";
}

interface AgentStatus {
	agent: string;
	model: string;
	agentSource: "user" | "project" | "main";
}

const STATUS_KEY = "agent-status";

// ═══════════════════════════════════════════════════════════════════════════════
// AGENT DISCOVERY
// ═══════════════════════════════════════════════════════════════════════════════

function discoverAgents(cwd: string): { agents: AgentConfig[]; projectDir: string | null } {
	const userDir = path.join(getAgentDir(), "agents");
	let projectDir: string | null = null;

	// Find project agents dir
	let currentDir = cwd;
	while (currentDir !== path.dirname(currentDir)) {
		const candidate = path.join(currentDir, ".pi", "agents");
		if (fs.existsSync(candidate) && fs.statSync(candidate).isDirectory()) {
			projectDir = candidate;
			break;
		}
		currentDir = path.dirname(currentDir);
	}

	const loadAgents = (dir: string, source: "user" | "project"): AgentConfig[] => {
		if (!fs.existsSync(dir)) return [];

		const agents: AgentConfig[] = [];
		try {
			const files = fs.readdirSync(dir);
			for (const file of files) {
				if (!file.endsWith(".md")) continue;

				const filePath = path.join(dir, file);
				const content = fs.readFileSync(filePath, "utf-8");
				const { frontmatter } = parseFrontmatter<Record<string, string>>(content);

				if (!frontmatter.name || !frontmatter.description) continue;

				agents.push({
					name: frontmatter.name,
					description: frontmatter.description,
					tools: frontmatter.tools?.split(",").map((t: string) => t.trim()).filter(Boolean),
					model: frontmatter.model,
					source,
				});
			}
		} catch { /* ignore */ }

		return agents;
	};

	const userAgents = loadAgents(userDir, "user");
	const projectAgents = projectDir ? loadAgents(projectDir, "project") : [];

	const agentMap = new Map<string, AgentConfig>();
	for (const a of [...userAgents, ...projectAgents]) {
		agentMap.set(a.name, a);
	}

	return { agents: Array.from(agentMap.values()), projectDir };
}

// ═══════════════════════════════════════════════════════════════════════════════
// STATUS MANAGEMENT
// ═══════════════════════════════════════════════════════════════════════════════

let currentStatus: AgentStatus = {
	agent: "main",
	model: "",
	agentSource: "main",
};

function getStatus(): AgentStatus {
	return currentStatus;
}

function setStatus(status: Partial<AgentStatus>) {
	currentStatus = { ...currentStatus, ...status };
}

// ═══════════════════════════════════════════════════════════════════════════════
// FOOTER RENDERING
// ═══════════════════════════════════════════════════════════════════════════════

function formatStatusLine(status: AgentStatus, theme: any): string {
	const agentIcon = "🤖";
	const modelIcon = "🧠";

	let agentText: string;
	let modelText: string;

	if (status.agent === "main") {
		agentText = theme.fg("accent", "main");
		modelText = status.model ? theme.fg("muted", status.model.split("/").pop() || status.model) : theme.fg("dim", "no model");
	} else {
		agentText = theme.fg("accent", status.agent);
		modelText = status.model ? theme.fg("muted", status.model.split("/").pop() || status.model) : theme.fg("dim", "default");
	}

	const sourceColor = status.agentSource === "project" ? theme.fg("warning", "[P]") :
						status.agentSource === "user" ? theme.fg("dim", "[U]") : "";

	return `${agentIcon} ${agentText} ${sourceColor}  |  ${modelIcon} ${modelText}`;
}

// ═══════════════════════════════════════════════════════════════════════════════
// EXTENSION
// ═══════════════════════════════════════════════════════════════════════════════

export default function (pi: ExtensionAPI) {
	// ─────────────────────────────────────────────────────────────────────────────
	// EVENT HANDLERS
	// ─────────────────────────────────────────────────────────────────────────────

	// Track model changes
	pi.on("model_select", async (event, ctx) => {
		const model = `${event.model.provider}/${event.model.id}`;
		setStatus({ model });

		if (ctx.hasUI && ctx.ui.setFooter) {
			const theme = ctx.ui.getTheme?.() || {};
			const line = formatStatusLine(getStatus(), theme);
			ctx.ui.setFooter("agent-status", line, {
				onClick: () => handleFooterClick(ctx),
			});
		}
	});

	// Track session start - restore status
	pi.on("session_start", async (_event, ctx) => {
		// Check for stored status in session
		const entries = ctx.sessionManager.getEntries();
		for (const entry of entries) {
			if (entry.type === "custom" && entry.customType === STATUS_KEY) {
				const data = entry.data as AgentStatus;
				setStatus(data);
				break;
			}
		}

		// Get current model
		if (ctx.model) {
			setStatus({ model: `${ctx.model.provider}/${ctx.model.id}` });
		}

		if (ctx.hasUI && ctx.ui.setFooter) {
			updateFooter(ctx);
		}
	});

	// Track agent changes via subagent tool results
	pi.on("tool_result", async (event, ctx) => {
		if (event.toolName !== "subagent") return;

		// Parse agent info from subagent results
		try {
			const content = event.content;
			if (Array.isArray(content) && content[0]?.type === "text") {
				const details = (event as any).details;
				if (details?.results?.length > 0) {
					const result = details.results[0];
					setStatus({
						agent: result.agent,
						model: result.model || getStatus().model,
						agentSource: result.agentSource || "user",
					});

					if (ctx.hasUI && ctx.ui.setFooter) {
						updateFooter(ctx);
					}
				}
			}
		} catch { /* ignore parse errors */ }
	});

	// ─────────────────────────────────────────────────────────────────────────────
	// FOOTER UPDATE
	// ─────────────────────────────────────────────────────────────────────────────

	function updateFooter(ctx: any) {
		const status = getStatus();
		const theme = ctx.ui.getTheme?.() || {};
		const line = formatStatusLine(status, theme);

		ctx.ui.setFooter("agent-status", line, {
			onClick: () => handleFooterClick(ctx),
		});
	}

	// ─────────────────────────────────────────────────────────────────────────────
	// INTERACTIVE HANDLERS
	// ─────────────────────────────────────────────────────────────────────────────

	async function handleFooterClick(ctx: any) {
		const { agents } = discoverAgents(ctx.cwd);

		// Show options: Change Agent, Change Model, Back to Main
		const options = [
			{ label: "🔄 Change Agent", value: "agent", description: "Switch to different agent" },
			{ label: "🤖 Back to Main", value: "main", description: "Return to main session (no subagent)" },
		];

		const choice = await ctx.ui.select("Agent Status", options);

		if (!choice) return;

		if (choice === "main") {
			setStatus({ agent: "main", agentSource: "main" });
			ctx.ui.notify("Returned to main session", "info");
			updateFooter(ctx);
			return;
		}

		if (choice === "agent") {
			await selectAgent(ctx, agents);
		}
	}

	async function selectAgent(ctx: any, agents: AgentConfig[]) {
		if (agents.length === 0) {
			ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "info");
			return;
		}

		const options = agents.map((a) => ({
			label: a.name,
			description: `${a.description} ${a.model ? `(model: ${a.model})` : ""}`,
			value: a.name,
		}));

		const selected = await ctx.ui.select("Select Agent:", options);

		if (!selected) return;

		const agent = agents.find((a) => a.name === selected);
		if (!agent) return;

		setStatus({
			agent: agent.name,
			model: agent.model || getStatus().model,
			agentSource: agent.source,
		});

		ctx.ui.notify(`Switched to agent: ${agent.name}`, "info");
		updateFooter(ctx);
	}

	// ─────────────────────────────────────────────────────────────────────────────
	// COMMANDS
	// ─────────────────────────────────────────────────────────────────────────────

	// Quick agent switch command
	pi.registerCommand("agent", {
		description: "Show or switch current agent",
		handler: async (args, ctx) => {
			const status = getStatus();

			if (!args.trim()) {
				// Show current status
				const theme = ctx.ui.getTheme?.() || {};
				ctx.ui.notify(
					`Current: 🤖 ${status.agent} | 🧠 ${status.model}`,
					"info",
				);
				return;
			}

			// Switch to specified agent
			const { agents } = discoverAgents(ctx.cwd);

			// Check if it's a valid agent name
			const agent = agents.find((a) => a.name === args.trim());

			if (!agent) {
				const available = agents.map((a) => a.name).join(", ") || "none";
				ctx.ui.notify(`Unknown agent. Available: ${available}`, "error");
				return;
			}

			setStatus({
				agent: agent.name,
				model: agent.model || getStatus().model,
				agentSource: agent.source,
			});

			updateFooter(ctx);
			ctx.ui.notify(`Switched to agent: ${agent.name}`, "info");
		},
	});

	// List agents command
	pi.registerCommand("agents", {
		description: "List available agents",
		handler: async (_args, ctx) => {
			const { agents, projectDir } = discoverAgents(ctx.cwd);
			const status = getStatus();

			if (agents.length === 0) {
				ctx.ui.notify("No agents configured. See ~/.pi/agent/agents/", "info");
				return;
			}

			const lines: string[] = [];
			lines.push(`Current: 🤖 ${status.agent}`);
			lines.push("");
			lines.push("Available agents:");
			lines.push("");

			for (const agent of agents) {
				const marker = agent.name === status.agent ? "→ " : "  ";
				const source = agent.source === "project" ? " [P]" : "";
				const model = agent.model ? ` (${agent.model.split("/").pop()})` : "";
				lines.push(`${marker}${agent.name}${source}${model}`);
				lines.push(`    ${agent.description}`);
				lines.push("");
			}

			if (projectDir) {
				lines.push(`Project agents from: ${projectDir}`);
			}

			lines.push("");
			lines.push("Use /agent <name> to switch");

			ctx.ui.setWidget("agents-list", lines);
		},
	});

	// ─────────────────────────────────────────────────────────────────────────────
	// TOOL FOR LLM
	// ─────────────────────────────────────────────────────────────────────────────

	pi.registerTool({
		name: "get_agent_status",
		label: "Get Agent Status",
		description: "Get current agent and model status",
		parameters: {
			type: "object",
			properties: {},
		},
		async execute() {
			const status = getStatus();
			return {
				content: [{
					type: "text",
					text: `Current agent: ${status.agent} (${status.agentSource})\nCurrent model: ${status.model || "default"}`,
				}],
				details: status,
			};
		},
	});

	pi.registerTool({
		name: "set_agent",
		label: "Set Agent",
		description: "Switch to a different agent",
		parameters: {
			type: "object",
			properties: {
				agent: { type: "string", description: "Agent name to switch to" },
			},
			required: ["agent"],
		},
		async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
			const { agents } = discoverAgents(ctx.cwd);
			const agent = agents.find((a) => a.name === params.agent);

			if (!agent) {
				const available = agents.map((a) => a.name).join(", ");
				return {
					content: [{
						type: "text",
						text: `Agent "${params.agent}" not found. Available: ${available || "none"}`,
					}],
					isError: true,
				};
			}

			setStatus({
				agent: agent.name,
				model: agent.model || getStatus().model,
				agentSource: agent.source,
			});

			updateFooter(ctx);

			return {
				content: [{
					type: "text",
					text: `Switched to agent: ${agent.name}`,
				}],
				details: getStatus(),
			};
		},
	});
}

